if (!issues.length) {
    core.notice(`No linked issues found for pull request #${ process.env.PULL_REQUEST_NUMBER }`);
    return;
}

core.info(`Found ${ issues.length } issue(s): ${ issues.join(', ') || '-' }`);

return issues;
